arguments.argument:
if fadingTime>0
{
  if signSize=0 {tBoxOffsetX=140}
  else if signSize=1 {tBoxOffsetX=200}
  else if signSize=2 {tBoxOffsetX=260}
  else if signSize=3 {tBoxOffsetX=320}
  
  if x<0 {x=0}
  else if x+tBoxOffsetX>room_width {x=room_width-tBoxOffsetX}
  fadingTime-=1
  if fadingTime<=20
    image_alpha-=0.05
}
else
  instance_destroy()
